SELECT count(*) FROM cast_info, title, char_name, name, movie_companies, kind_type, movie_info, info_type, aka_name WHERE cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND aka_name.person_id = name.id;